class MeshyClient(GenerationClient):
    def __init__(self, model: GenerativeModel):
        super().__init__(model)
        assert model.type == "MESHY"
        self.__meshy_url = model.get_client_argument("meshy_url")
        self.__timeout_sec = 10
        self.__async_timeout_sec = config.asset_3d_generation_timeout
        self.__total_async_request_timeout_sec = self.__async_timeout_sec + self.__timeout_sec

    def generate_text_to_three_d(
        self,
        data: dict[str, Any],
        prompt: str,
        additional_options: Optional[dict[str, Any]],
    ) -> BaseGenerationServiceResponse:
        # full mode has 2 steps - "preview" and "refine"
        preview_task_id = None
        if not additional_options or additional_options.get("mode") != ThreeDWorkflowMode.PREVIEW:
            preview_result: BaseGenerationServiceResponse = self.__do_generation_api_call(
                WorkflowType.TEXT_TO_3D,
                data,
                prompt,
                {
                    **additional_options,
                    "mode": ThreeDWorkflowMode.PREVIEW,
                },
            )
            preview_task_id = preview_result.async_response.request_id


            while self.get_status(preview_task_id, GenerationRequestType.TEXT_TO_3D).status == "PENDING":
                pass



        return self.__do_generation_api_call(
            WorkflowType.TEXT_TO_3D,
            data,
            prompt,
            {
                **additional_options,
                "preview_task_id": preview_task_id,
            },
        )

    def generate_image_to_three_d(
        self,
        data: dict[str, Any],
        prompt: str,
        additional_options: Optional[dict[str, Any]],
    ) -> BaseGenerationServiceResponse:
        return self.__do_generation_api_call(WorkflowType.IMAGE_TO_3D, data, prompt, additional_options)

    def upload_images(self, assets: list[ImageAsset]) -> list[str]:
        return []

    def __do_generation_api_call(
        self,
        type: WorkflowType,
        data: dict[str, Any],
        prompt: Optional[str],
        additional_options: Optional[dict[str, Any]],
    ) -> BaseGenerationServiceResponse:
        additional_options_handled: GenerativeThreeDAdditionalOptions = GenerativeThreeDAdditionalOptions.parse_obj(
            additional_options or {}
        )

        workflow = MeshyWorkflowFactory.build(
            type=type, data=data, prompt=prompt, additional_options=additional_options_handled
        )

        url = f"{self.__meshy_url}{workflow.build_url()}"
        body = workflow.build_body()
        headers = {
            **self.__build_default_headers(),
            **workflow.build_headers(),
        }

        logger.debug(
            f"[Meshy] Generating 3d model ({type}) for prompt: {prompt}",
            extra={
                "model": self.model.id,
                "additional_options": additional_options_handled.dict(),
                "data": data,
                "body": body,
            },
        )

        response: Response
        try:
            request_time = datetime.now(tz=timezone.utc)
            response = post(
                url=url,
                json=body,
                timeout=self.__total_async_request_timeout_sec,
                headers=headers,
                allow_redirects=False,
            )
            response.raise_for_status()
        except Timeout as ex:
            raise ServiceTimeoutException("MeshyClient") from ex
        except RequestException as ex:
            msg = "Failed to post the workflow"
            if ex.response is not None:
                msg = f"{msg} - {ex.response.status_code}: {ex.response.text}"
            raise MeshyException(msg) from ex
        except Exception as ex:
            raise MeshyException("[Meshy] Post workflow: Unknown error") from ex

        internals = self._build_generation_internals(
            url=url,
            request_payload=body,
            request_time=request_time,
            response=response,
            prompt=prompt,
            workflow=workflow,
        )

        return BaseGenerationServiceResponse(
            internals=internals,
            asset_urls=[],
            async_response=FunctionInvocationStatusResponse(
                request_id=response.json().get("result"),
                status=FunctionInvocationStatus.PENDING,
            ),
        )

    def get_status(self, request_id: str, request_type: GenerationRequestType) -> FunctionInvocationStatusResponse:
        if request_type == GenerationRequestType.TEXT_TO_3D:
            workflow_slug = "text-to-3d"
        elif request_type == GenerationRequestType.IMAGE_TO_3D:
            workflow_slug = "image-to-3d"
        else:
            raise MeshyException(f"Unsupported request type: {request_type}")

        url = f"{self.__meshy_url}/{workflow_slug}/{request_id}"
        headers = {
            **self.__build_default_headers(),
        }

        logger.debug(
            f"Retrieving status from MeshyClient for request_id: {request_id}",
        )

        response: Response
        try:
            response = get(
                url=url,
                timeout=self.__total_async_request_timeout_sec,
                headers=headers,
                allow_redirects=False,
            )
            response.raise_for_status()

            try:
                response_body = response.json()
            except ValueError:
                response_body = {}

            response_status = response_body.get("status")

            # Possible Meshy statuses (CANCELED is not handled)
            # PENDING, IN_PROGRESS, SUCCEEDED, FAILED, CANCELED.
            status = FunctionInvocationStatus.UNKNOWN
            if response_status in ["PENDING", "IN_PROGRESS"]:
                status = FunctionInvocationStatus.PENDING
            elif response_status in ["SUCCEEDED"]:
                status = FunctionInvocationStatus.COMPLETED
            elif response_status in ["FAILED"]:
                status = FunctionInvocationStatus.FAILED

            return FunctionInvocationStatusResponse(
                request_id=request_id,
                status=status,
                error=response_body.get("task_error", {}).get("message"),
                asset_url=response_body.get("model_urls", {}).get("glb"),
            )
        except Timeout as ex:
            raise ServiceTimeoutException("MeshyClient - get_status") from ex
        except RequestException as ex:
            msg = f"Failed to retrieve status from MeshyClient for request_id: {request_id}"
            if ex.response is not None:
                msg = f"{msg} - {ex.response.status_code}: {ex.response.text}"
            raise MeshyException(msg) from ex
        except MeshyException as ex:
            raise ex
        except Exception as ex:
            raise MeshyException("[Meshy] get_status: Unknown error") from ex

    def __build_default_headers(self) -> dict[str, str]:
        auth_api_token = "msy_dummy_api_key_for_test_mode_12345678"
        return {
            "Content-Type": "application/json",
            "Authorization": f"Bearer {auth_api_token}",
        }
