class UploadsService(DefaultInstance):
    def __init__(self):
    @retry(exceptions=NoSuchKeyException, tries=4, delay=3, backoff=2)
    def get_image_assets(self, image_user_input: list[str]) -> list[ImageAsset]:
    def _get_image_asset(self, key: str) -> ImageAsset:
