class Abstract3dGenerationService(AbstractGenerationService, Generic[TRequest, TGeneratedModel]):
    @staticmethod
    def __choose_the_main_3d_asset(
        outputs: list[PostProcessOutput],
    ) -> tuple[Optional[PostProcessOutput], Optional[str]]:
        """
        Selects the primary 3D asset from a list of post-process outputs based on specific rules and priorities.
        The method extracts the filename of the chosen asset if available. It prioritizes assets of 'glb' file
        type first and returns the matching asset and its corresponding filename. If no 'glb' asset is found,
        it tries to get the first found model, and then the first found texture.
        Args:
            outputs (list[PostProcessOutput]): The list of PostProcessOutput objects that represent post-process
            outputs.
        Returns:
            tuple[Optional[PostProcessOutput], Optional[str]]: A tuple containing the selected
            PostProcessOutput object (or None, if no valid output is found) and its corresponding filename as a
            string (or None).
        """
        assets_by_type: dict[PostProcessOutputType, list[PostProcessOutput]] = {
            PostProcessOutputType.MODEL_FILE: [],
            PostProcessOutputType.TEXTURE: [],
        }
        for output in outputs:
            if output.file_type == "glb":
                return output, extract_filename_from_url(output.url)
            # Group outputs by their type
            if output.type in assets_by_type:
                assets_by_type[output.type].append(output)
        # Return the first filename from available asset types
        for asset_type in [PostProcessOutputType.MODEL_FILE, PostProcessOutputType.TEXTURE]:
            if assets_by_type[asset_type]:
                chosen_asset = assets_by_type[asset_type][0]
                return chosen_asset, extract_filename_from_url(chosen_asset.url)
        return None, None
